        }

        footer {
            margin-top: 60px;
            font-size: 0.9em;
            opacity: 0.7;
            text-align: center;
        }

        /* Responsive adjustments */
        @media (max-width: 768px) {
            h1 {
                font-size: 2.5em;
            }
            p {
                font-size: 1em;
                padding: 0 10px;
            }
            .theme-toggle-button {
                padding: 10px 20px;
                font-size: 0.9em;
            }
        }

        @media (max-width: 480px) {
            h1 {
                font-size: 2em;
            }
            footer {
                font-size: 0.8em;
            }
        }
    </style>
</head>
